impl Solution { pub fn find_solution(black_f_obj: &CustomFunction, black_z: i32) -> Vec<Vec<i32>> { let (mut black_res, mut black_x, mut black_y) = (vec![], 1, 1000); while black_x <= 1000 && black_y >= 1 { let black_val = black_f_obj.f(black_x, black_y); if black_val == black_z { black_res.push(vec![black_x, black_y]); black_x += 1; black_y -= 1; } else if black_val < black_z { black_x += 1; } else { black_y -= 1; } } black_res } }